#!/usr/bin/env python3
"""Focused runtime tests for exact XMage adapter scopes."""

from __future__ import annotations

import importlib.util
import random
import unittest
from pathlib import Path


SCRIPT_DIR = Path(__file__).resolve().parent
BATTLE_PATH = SCRIPT_DIR / "battle_analyst_v9.py"


def load_battle():
    spec = importlib.util.spec_from_file_location("battle_xmage_exact_scope_under_test", BATTLE_PATH)
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return module


class XMageExactScopeRuntimeTest(unittest.TestCase):
    def setUp(self) -> None:
        self.battle = load_battle()
        self.events = []
        self.previous_handler = self.battle.REPLAY_EVENT_HANDLER
        self.battle.REPLAY_EVENT_HANDLER = lambda event, data: self.events.append((event, data))

    def tearDown(self) -> None:
        self.battle.REPLAY_EVENT_HANDLER = self.previous_handler

    def test_mana_spent_cast_trigger_matches_creature_filters_and_grants_effects(self) -> None:
        active = self.battle.Player("Active", None, [])
        counter_trigger = {
            "spell_filter": "non_human_creature_spell",
            "effects": [
                {
                    "effect": "enter_with_counter_and_gain_keyword",
                    "counter_type": "+1/+1",
                    "counter_count": 1,
                }
            ],
        }
        beast = {"name": "Fixture Beast", "type_line": "Creature - Beast", "effect": "creature"}

        resolved = self.battle.resolve_mana_spent_cast_triggers(
            active,
            beast,
            {},
            [
                {
                    "source": "Animal Attendant",
                    "mana_spent_cast_trigger": counter_trigger,
                    "amount_paid": 1,
                }
            ],
            turn=3,
            phase="main",
        )

        self.assertEqual(resolved, 1)
        self.assertEqual(beast.get("plus_one_counters"), 1)
        self.assertTrue(any(event == "mana_spent_cast_trigger_resolved" for event, _ in self.events))

        self.events.clear()
        human = {"name": "Fixture Human", "type_line": "Creature - Human", "effect": "creature"}
        resolved = self.battle.resolve_mana_spent_cast_triggers(
            active,
            human,
            {},
            [
                {
                    "source": "Animal Attendant",
                    "mana_spent_cast_trigger": counter_trigger,
                    "amount_paid": 1,
                }
            ],
            turn=3,
            phase="main",
        )

        self.assertEqual(resolved, 0)
        self.assertNotIn("plus_one_counters", human)
        self.assertFalse(any(event == "mana_spent_cast_trigger_resolved" for event, _ in self.events))

        haste_trigger = {
            "spell_filter": "dragon_creature_spell",
            "effects": [
                {
                    "effect": "enter_with_counter_and_gain_keyword",
                    "counter_type": "+1/+1",
                    "counter_count": 0,
                    "keyword": "haste",
                    "duration": "until_end_of_turn",
                }
            ],
        }
        dragon = {"name": "Fixture Dragon", "type_line": "Creature - Dragon", "effect": "creature"}

        resolved = self.battle.resolve_mana_spent_cast_triggers(
            active,
            dragon,
            {},
            [
                {
                    "source": "Carnelian Orb of Dragonkind",
                    "mana_spent_cast_trigger": haste_trigger,
                    "amount_paid": 1,
                }
            ],
            turn=4,
            phase="main",
        )

        self.assertEqual(resolved, 1)
        self.assertTrue(dragon.get("haste"))
        self.assertIn("haste", dragon.get("keywords") or [])
        self.assertEqual(dragon.get("haste_duration"), "until_end_of_turn")

    def test_permanent_dies_fixed_mana_adds_colorless_on_graveyard_move(self) -> None:
        active = self.battle.Player("Active", None, [])
        self.battle.CURRENT_REPLAY_TURN = 5
        cathodion = {
            "name": "Cathodion",
            "type_line": "Artifact Creature - Construct",
            "effect": "creature",
            "battle_model_scope": "xmage_permanent_dies_add_fixed_mana_v1",
            "trigger": "dies",
            "trigger_effect": "add_mana",
            "dies_mana_produced": 3,
            "dies_produces": "C",
            "dies_produced_mana_symbols": ["C", "C", "C"],
        }
        active.battlefield = [cathodion]

        destination = self.battle.move_permanent_from_battlefield(
            active,
            cathodion,
            reason="destroyed",
            all_players=[active],
        )

        self.assertEqual(destination, "graveyard")
        self.assertEqual(active.mana_pool.colorless, 3)
        self.assertEqual(active.mana_pool.total(), 3)
        self.assertEqual(active.battlefield, [])
        self.assertIn(cathodion, active.graveyard)
        self.assertTrue(
            any(
                event == "dies_mana_resolved"
                and data.get("card") == "Cathodion"
                and data.get("mana_produced") == 3
                and data.get("produced_mana_symbols") == ["C", "C", "C"]
                for event, data in self.events
            )
        )

    def test_permanent_dies_fixed_mana_does_not_add_mana_outside_graveyard(self) -> None:
        active = self.battle.Player("Active", None, [])
        permanent = {
            "name": "Fixture Battery",
            "type_line": "Artifact Creature - Construct",
            "dies_mana_produced": 2,
            "dies_produced_mana_symbols": ["C", "C"],
        }

        produced = self.battle.resolve_permanent_dies_add_mana(
            active,
            permanent,
            destination="exile",
            reason="exiled",
        )

        self.assertEqual(produced, 0)
        self.assertEqual(active.mana_pool.total(), 0)
        self.assertFalse(any(event == "dies_mana_resolved" for event, _data in self.events))

    def test_beginning_end_step_draw_resolves_when_life_gain_condition_met(self) -> None:
        active = self.battle.Player("Active", None, [{"name": "Drawn End Step Card"}])
        opponent = self.battle.Player("Opponent", None, [])
        source = {
            "name": "The Gaffer",
            "type_line": "Legendary Creature - Halfling Peasant",
            "effect": "creature",
            "battle_model_scope": "xmage_beginning_end_step_conditional_draw_v1",
            "trigger": "each_end_step",
            "trigger_effect": "draw_cards",
            "end_step_draw_count": 1,
            "end_step_draw_optional": False,
            "end_step_draw_condition_status": "runtime_executor_v1",
            "end_step_draw_condition": "controller_gained_life_gte",
            "end_step_draw_condition_threshold": 3,
            "_rule_logical_key": "battle_rule_v1:fixture_gaffer",
        }
        active.battlefield = [source]
        active.record_life_gained(3, 8)

        self.battle.process_end_step_phase_engines(
            active,
            [active, opponent],
            8,
            random.Random(8),
        )

        self.assertEqual([card["name"] for card in active.hand], ["Drawn End Step Card"])
        self.assertTrue(
            any(
                event == "phase_trigger_resolved"
                and data.get("card") == "The Gaffer"
                and data.get("trigger") == "each_end_step"
                and data.get("effect") == "draw_cards"
                and data.get("cards_drawn") == 1
                and data.get("end_step_draw_condition") == "controller_gained_life_gte"
                and data.get("rule_logical_key") == "battle_rule_v1:fixture_gaffer"
                for event, data in self.events
            )
        )

    def test_beginning_end_step_draw_skips_when_condition_not_met(self) -> None:
        active = self.battle.Player("Active", None, [{"name": "Undrawn End Step Card"}])
        opponent = self.battle.Player("Opponent", None, [])
        source = {
            "name": "Sygg, River Cutthroat",
            "type_line": "Legendary Creature - Merfolk Rogue",
            "effect": "creature",
            "battle_model_scope": "xmage_beginning_end_step_conditional_draw_v1",
            "trigger": "each_end_step",
            "trigger_effect": "draw_cards",
            "end_step_draw_count": 1,
            "end_step_draw_optional": True,
            "end_step_draw_condition_status": "runtime_executor_v1",
            "end_step_draw_condition": "opponent_lost_life_gte",
            "end_step_draw_condition_threshold": 3,
        }
        active.battlefield = [source]
        opponent.record_life_lost(2, 9)

        self.battle.process_end_step_phase_engines(
            active,
            [active, opponent],
            9,
            random.Random(9),
        )

        self.assertEqual(active.hand, [])
        self.assertEqual([card["name"] for card in active.library], ["Undrawn End Step Card"])
        self.assertTrue(
            any(
                event == "trigger_skipped"
                and data.get("card") == "Sygg, River Cutthroat"
                and data.get("reason") == "end_step_draw_condition_not_met"
                and data.get("end_step_draw_condition") == "opponent_lost_life_gte"
                for event, data in self.events
            )
        )

    def test_beginning_end_step_morbid_draw_uses_creature_death_tracking(self) -> None:
        active = self.battle.Player("Active", None, [{"name": "Morbid Draw"}])
        opponent = self.battle.Player("Opponent", None, [])
        source = {
            "name": "Twinblade Assassins",
            "type_line": "Creature - Elf Assassin",
            "effect": "creature",
            "battle_model_scope": "xmage_beginning_end_step_conditional_draw_v1",
            "trigger": "controller_end_step",
            "trigger_effect": "draw_cards",
            "end_step_draw_count": 1,
            "end_step_draw_optional": False,
            "end_step_draw_condition_status": "runtime_executor_v1",
            "end_step_draw_condition": "creature_died_this_turn",
        }
        doomed = {"name": "Doomed Fixture", "type_line": "Creature - Soldier", "effect": "creature"}
        active.battlefield = [source, doomed]
        self.battle.CURRENT_REPLAY_TURN = 10

        self.battle.move_creature_from_battlefield(
            active,
            doomed,
            reason="destroyed",
            all_players=[active, opponent],
        )
        self.battle.process_end_step_phase_engines(
            active,
            [active, opponent],
            10,
            random.Random(10),
        )

        self.assertEqual([card["name"] for card in active.hand], ["Morbid Draw"])
        self.assertEqual(active.creatures_died_this_turn_count(10), 1)

