    def test_simple_activated_regenerate_source_consumes_shield_on_destroy(self) -> None:
        active = self.battle.Player("Active", None, [])
        self.battle.CURRENT_REPLAY_TURN = 8
        troll = {
            "name": "Cudgel Troll",
            "type_line": "Creature - Troll",
            "effect": "creature",
            "power": 4,
            "toughness": 3,
            "battle_model_scope": "xmage_permanent_simple_activated_regenerate_source_v1",
            "activated_effect": "regenerate_source",
            "activated_battle_model_scope": "xmage_permanent_simple_activated_regenerate_source_v1",
            "target": "self",
            "target_controller": "self",
            "target_constraints": {"source": "self", "card_types": ["creature"]},
            "regenerate_source": True,
            "activation_cost_mana": "{G}",
            "activation_cost_generic": 0,
            "activation_cost_colors": ["G"],
            "activation_requires_tap": False,
        }
        active.battlefield = [troll]
        active.mana_pool.add("green", 1)

        self.assertTrue(self.battle.can_activate_generic_regenerate_source_permanent(active, troll))
        self.assertTrue(
            self.battle.activate_generic_regenerate_source_permanent(
                active,
                [active],
                troll,
                turn=8,
                rng=random.Random(1),
            )
        )
        self.assertEqual(active.mana_pool.total(), 0)
        self.assertEqual(troll.get("regeneration_shields"), 1)

        destination = self.battle.move_creature_from_battlefield(
            active,
            troll,
            reason="destroy",
            source={"name": "E2E Doom Blade"},
            all_players=[active],
        )

        self.assertEqual(destination, "battlefield")
        self.assertIn(troll, active.battlefield)
        self.assertNotIn(troll, active.graveyard)
        self.assertTrue(troll.get("tapped"))
        self.assertEqual(troll.get("regeneration_shields"), 0)
        self.assertTrue(
            any(
                event == "regeneration_shield_used"
                and data.get("card") == "Cudgel Troll"
                and data.get("destination") == "battlefield"
                for event, data in self.events
            )
        )

    def test_simple_activated_regenerate_source_preserves_static_keywords(self) -> None:
        active = self.battle.Player("Active", None, [])
        spirit = {
            "name": "Fixture Skyguard",
            "type_line": "Creature - Spirit Knight",
            "effect": "creature",
            "power": 2,
            "toughness": 2,
            "battle_model_scope": "xmage_permanent_simple_activated_regenerate_source_v1",
            "activated_effect": "regenerate_source",
            "activated_battle_model_scope": "xmage_permanent_simple_activated_regenerate_source_v1",
            "target": "self",
            "target_controller": "self",
            "target_constraints": {"source": "self", "card_types": ["creature"]},
            "regenerate_source": True,
            "activation_cost_mana": "{W}",
            "activation_cost_generic": 0,
            "activation_cost_colors": ["W"],
            "activation_requires_tap": False,
            "keywords": ["flying", "vigilance"],
            "_keywords_are_self": True,
            "flying": True,
            "vigilance": True,
        }
        permanent = self.battle.enrich_card(dict(spirit))
        permanent["effect"] = "creature"
        active.battlefield = [permanent]
        active.mana_pool.add("white", 1)

        self.assertTrue(permanent["flying"])
        self.assertTrue(self.battle.has_vigilance(permanent))
        self.assertTrue(self.battle.can_activate_generic_regenerate_source_permanent(active, permanent))
        self.assertTrue(
            self.battle.activate_generic_regenerate_source_permanent(
                active,
                [active],
                permanent,
                turn=9,
                rng=random.Random(9),
            )
        )
        self.assertEqual(permanent.get("regeneration_shields"), 1)

    def test_direct_damage_reports_creature_regenerated_when_shield_replaces_destroy(self) -> None:
        active = self.battle.Player("Active", None, [])
        opponent = self.battle.Player("Opponent", None, [])
        self.battle.CURRENT_REPLAY_TURN = 9
        troll = {
            "name": "Shielded Troll",
            "type_line": "Creature - Troll",
            "effect": "creature",
            "power": 2,
            "toughness": 2,
            "regeneration_shields": 1,
        }
        opponent.battlefield = [troll]

        self.battle.apply_direct_damage(
            active,
            [opponent],
            {"name": "E2E Lightning Bolt", "type_line": "Instant"},
            {"effect": "direct_damage", "amount": 3, "target": "creature"},
            turn=9,
            rng=random.Random(2),
        )

        self.assertIn(troll, opponent.battlefield)
        self.assertNotIn(troll, opponent.graveyard)
        self.assertTrue(troll.get("tapped"))
        self.assertEqual(troll.get("regeneration_shields"), 0)
        self.assertTrue(
            any(
                event == "damage_resolved"
                and data.get("target") == "Shielded Troll"
                and data.get("result") == "creature_regenerated"
                and data.get("destination") == "battlefield"
                for event, data in self.events
            )
        )

    def test_destroy_target_controller_life_loss_applies_after_destroy(self) -> None:
        active = self.battle.Player("Active", None, [])
        opponent = self.battle.Player("Opponent", None, [])
        opponent.life = 20
        land = {
            "name": "Fixture Mine",
            "type_line": "Land",
        }
        opponent.battlefield = [land]
        effect = {
            "effect": "remove_permanent",
            "battle_model_scope": "xmage_destroy_target_and_target_controller_loses_life_spell_v1",
            "target": "land",
            "target_constraints": {"card_types": ["land"]},
            "destination": "graveyard",
            "target_controller_life_loss_on_destroy": 2,
        }

        self.battle.apply_effect_immediate(
            active,
            [opponent],
            {"name": "Fixture Despoil", "type_line": "Sorcery"},
            turn=10,
            rng=random.Random(10),
            effect_data_override=effect,
        )

        self.assertEqual(opponent.life, 18)
        self.assertEqual(opponent.battlefield, [])
        self.assertIn(land, opponent.graveyard)
        self.assertTrue(
            any(
                event == "life_loss_on_destroy_resolved"
                and data.get("card") == "Fixture Despoil"
                and data.get("target") == "Fixture Mine"
                and data.get("target_controller_life_lost") == 2
                for event, data in self.events
            )
        )

