    def test_fixed_draw_spell_pays_minus_one_counter_cost_before_draw(self) -> None:
        active = self.battle.Player("Active", None, [])
        opponent = self.battle.Player("Opponent", None, [])
        cost_creature = {
            "name": "Spare Scarab",
            "type_line": "Creature - Insect",
            "effect": "creature",
            "power": 2,
            "toughness": 2,
            "summoning_sick": True,
        }
        active.battlefield.append(cost_creature)
        active.library = [
            {"name": "Drawn Card A", "type_line": "Instant", "effect": "draw_cards", "cmc": 1},
            {"name": "Drawn Card B", "type_line": "Sorcery", "effect": "draw_cards", "cmc": 2},
        ]
        effect = {
            "effect": "draw_cards",
            "battle_model_scope": "xmage_fixed_source_controller_draw_spell_v1",
            "count": 2,
            "draw_count": 2,
            "requires_put_minus_one_counter_on_controlled_creature": True,
            "put_minus_one_counter_count": 1,
            "additional_cost": "put_minus_one_counter_on_controlled_creature",
            "sorcery": True,
        }

        self.battle.apply_effect_immediate(
            active,
            [opponent],
            {
                "name": "Scarscale Ritual",
                "type_line": "Sorcery",
                "oracle_text": (
                    "As an additional cost to cast this spell, put a -1/-1 counter "
                    "on a creature you control. Draw two cards."
                ),
            },
            turn=4,
            rng=random.Random(34),
            effect_data_override=effect,
        )

        self.assertIn(cost_creature, active.battlefield)
        self.assertEqual(cost_creature.get("minus_one_counters"), 1)
        self.assertEqual(len(active.library), 0)
        self.assertEqual([card.get("name") for card in active.hand], ["Drawn Card A", "Drawn Card B"])
        self.assertTrue(
            any(
                event == "additional_cost_paid"
                and data.get("card") == "Scarscale Ritual"
                and data.get("cost") == "put_minus_one_counter_on_controlled_creature"
                and data.get("countered_creature") == "Spare Scarab"
                and data.get("counter_type") == "-1/-1"
                and data.get("counters_added") == 1
                for event, data in self.events
            )
        )
        self.assertTrue(
            any(
                event == "draw_cards_resolved"
                and data.get("card") == "Scarscale Ritual"
                and data.get("cards_drawn") == 2
                for event, data in self.events
            )
        )

    def test_removal_compensation_creature_token_preserves_keywords_and_colors(self) -> None:
        active = self.battle.Player("Active", None, [])
        opponent = self.battle.Player("Opponent", None, [])
        target = {
            "name": "Target Knight",
            "type_line": "Creature - Knight",
            "effect": "creature",
            "power": 3,
            "toughness": 3,
        }
        opponent.battlefield.append(target)
        effect = {
            "effect": "remove_permanent",
            "battle_model_scope": "xmage_exile_target_with_controller_creature_token_compensation_spell_v1",
            "target": "creature_or_planeswalker",
            "target_constraints": {"card_types": ["creature", "planeswalker"]},
            "destination": "exile",
            "target_controller_creature_tokens": 1,
            "target_controller_token_name": "Angel Token",
            "target_controller_token_subtype": "Angel",
            "target_controller_token_power": 4,
            "target_controller_token_toughness": 4,
            "target_controller_token_colors": ["W"],
            "target_controller_token_keywords": ["flying"],
            "target_controller_token_flying": True,
            "declared_targets": [{"target": target, "controller": opponent}],
        }

        resolved = self.battle.resolve_declared_single_removal(
            active,
            [opponent],
            {"name": "Angelic Ascension", "type_line": "Instant"},
            effect,
            turn=4,
            rng=random.Random(44),
        )

        self.assertTrue(resolved)
        self.assertNotIn(target, opponent.battlefield)
        angel = next(card for card in opponent.battlefield if card.get("name") == "Angel Token")
        self.assertEqual(angel["type_line"], "Creature Token — Angel")
        self.assertEqual(angel["power"], 4)
        self.assertEqual(angel["toughness"], 4)
        self.assertEqual(angel["colors"], ["W"])
        self.assertEqual(angel["color_identity"], ["W"])
        self.assertEqual(angel["keywords"], ["flying"])
        self.assertTrue(angel["flying"])
        self.assertTrue(
            any(
                event == "compensation_tokens_created"
                and data.get("card") is None
                and data.get("source") == "Angelic Ascension"
                and data.get("token") == "Angel Token"
                and data.get("tokens_created") == 1
                for event, data in self.events
            )
        )

