        self.assertTrue(
            any(
                event == "spell_countered"
                and data.get("counter") == "Fixture Dissolve"
                and data.get("target") == "Target Threat"
                and data.get("scry_on_counter") == 1
                and data.get("scry_looked_at") == ["Top Card"]
                for event, data in self.events
            )
        )

